import subprocess
result = subprocess.run(['python', '-m', 'pip', 'list', '--format=columns'], capture_output=True, text=True, timeout=30)
print(result.stdout[:2000])
if result.stderr:
    print("STDERR:", result.stderr[:500])

# Also try direct import
import importlib
for pkg in ['spotpy', 'numpy', 'pandas', 'scipy']:
    try:
        importlib.import_module(pkg)
        print(f"✓ {pkg} is importable")
    except ImportError:
        print(f"✗ {pkg} is NOT importable")

